+                .timeout => "TIMEOUT",
+                .compile_fail => "COMPILE",
+            };
+            const color = switch (t.status) {
+                .failed => Color.red,
+                .timeout => Color.yellow,
+                .compile_fail => Color.red,
+            };
+            std.debug.print("  {s}[{s}]{s} {s}\n", .{ color, status_str, Color.reset, t.name });
         }
